// Constrain to range
clamp(150, 0, 100); // 100
clamp(-5, 0, 100); // 0

// Generate sequences
range(1, 5); // [1, 2, 3, 4, 5]
range(0, 10, 2); // [0, 2, 4, 6, 8, 10]

// Random numbers
randomInt(1, 100); // Random integer between 1-100
randomNum(1, 100); // Random float between 1-100

// Precise rounding
roundTo(3.14159, 2); // 3.14
